import{_ as e}from"./plugin-vue_export-helper.21dcd24c.js";import{d as n}from"./app.c6c89e20.js";const a={},p=n('<h1 id="openresty-\u66F4\u7075\u6D3B\u7684web\u670D\u52A1\u5668" tabindex="-1"><a class="header-anchor" href="#openresty-\u66F4\u7075\u6D3B\u7684web\u670D\u52A1\u5668" aria-hidden="true">#</a> OpenResty\uFF1A\u66F4\u7075\u6D3B\u7684Web\u670D\u52A1\u5668</h1><p>Nginx \u7684\u670D\u52A1\u7BA1\u7406\u601D\u8DEF\u5EF6\u7EED\u4E86\u5F53\u65F6\u7684\u6D41\u884C\u505A\u6CD5\uFF0C\u4F7F\u7528\u78C1\u76D8\u4E0A\u7684\u9759\u6001\u914D\u7F6E\u6587\u4EF6\uFF0C\u6240\u4EE5\u6BCF\u6B21\u4FEE\u6539\u540E\u5FC5\u987B\u91CD\u542F\u624D\u80FD\u751F\u6548\u3002</p><p>\u8FD9\u5728\u4E1A\u52A1\u9891\u7E41\u53D8\u52A8\u7684\u65F6\u5019\u662F\u975E\u5E38\u81F4\u547D\u7684\uFF08\u4F8B\u5982\u6D41\u884C\u7684\u5FAE\u670D\u52A1\u67B6\u6784\uFF09\uFF0C\u7279\u522B\u662F\u5BF9\u4E8E\u62E5\u6709\u6210\u5343\u4E0A\u4E07\u53F0\u670D\u52A1\u5668\u7684\u7F51\u7AD9\u6765\u8BF4\uFF0C\u4EC5\u4EC5\u589E\u52A0\u6216\u8005\u5220\u9664\u4E00\u884C\u914D\u7F6E\u5C31\u8981\u5206\u53D1\u3001\u91CD\u542F\u6240\u6709\u7684\u673A\u5668\uFF0C\u5BF9\u8FD0\u7EF4\u662F\u4E00\u4E2A\u975E\u5E38\u5927\u7684\u6311\u6218\uFF0C\u8981\u8017\u8D39\u5F88\u591A\u7684\u65F6\u95F4\u548C\u7CBE\u529B\uFF0C\u6210\u672C\u5F88\u9AD8\uFF0C\u5F88\u4E0D\u7075\u6D3B\uFF0C\u96BE\u4EE5\u201C\u968F\u9700\u5E94\u53D8\u201D\u3002</p><p>\u6709\u6CA1\u6709\u8FD9\u6837\u7684\u4E00\u4E2A Web \u670D\u52A1\u5668\uFF0C\u5B83\u6709 Nginx \u7684\u4F18\u70B9\u5374\u6CA1\u6709 Nginx \u7684\u7F3A\u70B9\uFF0C\u65E2\u8F7B\u91CF\u7EA7\u3001\u9AD8\u6027\u80FD\uFF0C\u53C8\u7075\u6D3B\u3001\u53EF\u52A8\u6001\u914D\u7F6E\u5462\uFF1F\u8FD9\u5C31\u662F OpenResty\uFF0C\u5B83\u662F\u4E00\u4E2A\u201C\u66F4\u597D\u66F4\u7075\u6D3B\u7684 Nginx\u201D\u3002</p><h2 id="openresty-\u662F\u4EC0\u4E48" tabindex="-1"><a class="header-anchor" href="#openresty-\u662F\u4EC0\u4E48" aria-hidden="true">#</a> OpenResty \u662F\u4EC0\u4E48\uFF1F</h2><p>OpenResty \u8BDE\u751F\u4E8E 2009 \u5E74\uFF0C\u5230\u73B0\u5728\u521A\u597D\u6EE1 10 \u5468\u5C81\u3002\u5B83\u7684\u521B\u9020\u8005\u662F\u5F53\u65F6\u5C31\u804C\u4E8E\u67D0\u5B9D\u7684\u201C\u795E\u7EA7\u201D\u7A0B\u5E8F\u5458\u7AE0\u4EA6\u6625\uFF0C\u7F51\u540D\u53EB\u201Cagentzh\u201D\u3002</p><p>OpenResty \u5E76\u4E0D\u662F\u4E00\u4E2A\u5168\u65B0\u7684 Web \u670D\u52A1\u5668\uFF0C\u800C\u662F\u57FA\u4E8E Nginx\uFF0C<strong>\u5B83\u5229\u7528\u4E86 Nginx \u6A21\u5757\u5316\u3001\u53EF\u6269\u5C55\u7684\u7279\u6027\uFF0C\u5F00\u53D1\u4E86\u4E00\u7CFB\u5217\u7684\u589E\u5F3A\u6A21\u5757\uFF0C\u5E76\u628A\u5B83\u4EEC\u6253\u5305\u6574\u5408\uFF0C\u5F62\u6210\u4E86\u4E00\u4E2A\u201C\u4E00\u7AD9\u5F0F\u201D\u7684 Web \u5F00\u53D1\u5E73\u53F0\u3002</strong></p><p>\u867D\u7136 OpenResty \u7684\u6838\u5FC3\u662F Nginx\uFF0C\u4F46\u5B83\u53C8\u8D85\u8D8A\u4E86 Nginx\uFF0C\u5173\u952E\u5C31\u5728\u4E8E\u5176\u4E2D\u7684 ngx_lua \u6A21\u5757\uFF0C\u628A\u5C0F\u5DE7\u7075\u6D3B\u7684 Lua \u8BED\u8A00\u5D4C\u5165\u4E86 Nginx\uFF0C\u53EF\u4EE5\u7528\u811A\u672C\u7684\u65B9\u5F0F\u64CD\u4F5C Nginx \u5185\u90E8\u7684\u8FDB\u7A0B\u3001\u591A\u8DEF\u590D\u7528\u3001\u9636\u6BB5\u5F0F\u5904\u7406\u7B49\u5404\u79CD\u6784\u4EF6\u3002</p><h3 id="\u52A8\u6001\u7684-lua" tabindex="-1"><a class="header-anchor" href="#\u52A8\u6001\u7684-lua" aria-hidden="true">#</a> \u52A8\u6001\u7684 Lua</h3><p>\u521A\u624D\u8BF4\u4E86\uFF0COpenResty \u91CC\u7684\u4E00\u4E2A\u5173\u952E\u6A21\u5757\u662F ngx_lua\uFF0C\u5B83\u4E3A Nginx \u5F15\u5165\u4E86\u811A\u672C\u8BED\u8A00 Lua\u3002Lua \u662F\u4E00\u4E2A\u6BD4\u8F83\u201C\u5C0F\u4F17\u201D\u7684\u8BED\u8A00\uFF0C\u867D\u7136\u5386\u53F2\u6BD4\u8F83\u60A0\u4E45\uFF0C\u4F46\u540D\u6C14\u5374\u6CA1\u6709 PHP\u3001Python\u3001JavaScript \u5927\uFF0C\u8FD9\u4E3B\u8981\u4E0E\u5B83\u7684\u81EA\u8EAB\u5B9A\u4F4D\u6709\u5173\u3002</p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/202205142057431.png" alt="img" style="zoom:25%;"><p>\u4F5C\u4E3A\u811A\u672C\u8BED\u8A00\uFF0CLua \u8FD8\u6709\u4E00\u4E2A\u91CD\u8981\u7684\u201C<strong>\u4EE3\u7801\u70ED\u52A0\u8F7D</strong>\u201D\u7279\u6027\uFF0C\u4E0D\u9700\u8981\u91CD\u542F\u8FDB\u7A0B\uFF0C\u5C31\u80FD\u591F\u4ECE\u78C1\u76D8\u3001Redis \u6216\u8005\u4EFB\u4F55\u5176\u4ED6\u5730\u65B9\u52A0\u8F7D\u6570\u636E\uFF0C\u968F\u65F6\u66FF\u6362\u5185\u5B58\u91CC\u7684\u4EE3\u7801\u7247\u6BB5\u3002\u8FD9\u5C31\u5E26\u6765\u4E86\u201C<strong>\u52A8\u6001\u914D\u7F6E</strong>\u201D\uFF0C\u8BA9 OpenResty \u80FD\u591F\u6C38\u4E0D\u505C\u673A\uFF0C\u5728\u5FAE\u79D2\u3001\u6BEB\u79D2\u7EA7\u522B\u5B9E\u73B0\u914D\u7F6E\u548C\u4E1A\u52A1\u903B\u8F91\u7684\u5B9E\u65F6\u66F4\u65B0\uFF0C\u6BD4\u8D77 Nginx \u79D2\u7EA7\u7684\u91CD\u542F\u662F\u4E00\u4E2A\u6781\u5927\u7684\u8FDB\u6B65\u3002</p><h3 id="\u9636\u6BB5\u5F0F\u5904\u7406" tabindex="-1"><a class="header-anchor" href="#\u9636\u6BB5\u5F0F\u5904\u7406" aria-hidden="true">#</a> \u9636\u6BB5\u5F0F\u5904\u7406</h3><p>\u548C Nginx \u4E00\u6837\uFF0COpenResty \u4E5F\u4F7F\u7528\u201C\u6D41\u6C34\u7EBF\u201D\u6765\u5904\u7406 HTTP \u8BF7\u6C42\uFF0C\u5E95\u5C42\u7684\u8FD0\u884C\u57FA\u7840\u662F Nginx \u7684\u201C\u9636\u6BB5\u5F0F\u5904\u7406\u201D\uFF0C\u4F46\u5B83\u53C8\u6709\u81EA\u5DF1\u7684\u7279\u8272\u3002</p><p>Nginx \u7684\u201C\u6D41\u6C34\u7EBF\u201D\u662F\u7531\u4E00\u4E2A\u4E2A C \u6A21\u5757\u7EC4\u6210\u7684\uFF0C\u53EA\u80FD\u5728\u9759\u6001\u6587\u4EF6\u91CC\u914D\u7F6E\uFF0C\u5F00\u53D1\u56F0\u96BE\uFF0C\u914D\u7F6E\u9EBB\u70E6\uFF08\u76F8\u5BF9\u800C\u8A00\uFF09\u3002\u800C OpenResty \u7684\u201C\u6D41\u6C34\u7EBF\u201D\u5219\u662F\u7531\u4E00\u4E2A\u4E2A\u7684 Lua \u811A\u672C\u7EC4\u6210\u7684\uFF0C\u4E0D\u4EC5\u53EF\u4EE5\u4ECE\u78C1\u76D8\u4E0A\u52A0\u8F7D\uFF0C\u4E5F\u53EF\u4EE5\u4ECE Redis\u3001MySQL \u91CC\u52A0\u8F7D\uFF0C\u800C\u4E14\u7F16\u5199\u3001\u8C03\u8BD5\u7684\u8FC7\u7A0B\u975E\u5E38\u65B9\u4FBF\u5FEB\u6377\u3002</p><p>\u56FE\u5217\u51FA\u4E86 OpenResty \u7684\u9636\u6BB5\uFF0C\u6BD4\u8D77 Nginx\uFF0COpenResty \u7684\u9636\u6BB5\u66F4\u6CE8\u91CD\u5BF9 HTTP \u8BF7\u6C42\u54CD\u5E94\u62A5\u6587\u7684\u52A0\u5DE5\u548C\u5904\u7406\u3002</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/202205142101511.png" alt="img" loading="lazy"></p><h2 id="\u5C0F\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u5C0F\u7ED3" aria-hidden="true">#</a> \u5C0F\u7ED3</h2><p>Nginx \u4F9D\u8D56\u4E8E\u78C1\u76D8\u4E0A\u7684\u9759\u6001\u914D\u7F6E\u6587\u4EF6\uFF0C\u4FEE\u6539\u540E\u5FC5\u987B\u91CD\u542F\u624D\u80FD\u751F\u6548\uFF0C\u7F3A\u4E4F\u7075\u6D3B\u6027\uFF1B</p><p>OpenResty \u57FA\u4E8E Nginx\uFF0C\u6253\u5305\u4E86\u5F88\u591A\u6709\u7528\u7684\u6A21\u5757\u548C\u5E93\uFF0C\u662F\u4E00\u4E2A\u9AD8\u6027\u80FD\u7684 Web \u5F00\u53D1\u5E73\u53F0\uFF1B</p><p>OpenResty \u7684\u5DE5\u4F5C\u8BED\u8A00\u662F Lua\uFF0C\u5B83\u5C0F\u5DE7\u7075\u6D3B\uFF0C\u6267\u884C\u6548\u7387\u9AD8\uFF0C\u652F\u6301\u201C\u4EE3\u7801\u70ED\u52A0\u8F7D\u201D\uFF1B</p><p>OpenResty \u7684\u6838\u5FC3\u7F16\u7A0B\u8303\u5F0F\u662F\u201C\u540C\u6B65\u975E\u963B\u585E\u201D\uFF0C\u4F7F\u7528\u534F\u7A0B\uFF0C\u4E0D\u9700\u8981\u5F02\u6B65\u56DE\u8C03\u51FD\u6570\uFF1B</p><p>OpenResty \u4E5F\u4F7F\u7528\u201C\u9636\u6BB5\u5F0F\u5904\u7406\u201D\u7684\u5DE5\u4F5C\u6A21\u5F0F\uFF0C\u4F46\u56E0\u4E3A\u5728\u9636\u6BB5\u91CC\u6267\u884C\u7684\u90FD\u662F Lua \u4EE3\u7801\uFF0C\u6240\u4EE5\u975E\u5E38\u7075\u6D3B\uFF0C\u914D\u5408 Redis \u7B49\u5916\u90E8\u6570\u636E\u5E93\u80FD\u591F\u5B9E\u73B0\u5404\u79CD\u52A8\u6001\u914D\u7F6E\u3002</p>',23);function t(s,i){return p}var h=e(a,[["render",t],["__file","OpenResty.html.vue"]]);export{h as default};
